}

export function getDashboardCostSummary(): DashboardCostSummary {
  type CostRow = { costToday: number; costMtd: number };
  const row = getDb()
    .prepare<CostRow, []>(
      `SELECT
        COALESCE(SUM(CASE WHEN createdAt >= date('now') THEN totalCostUsd ELSE 0 END), 0) as costToday,
