/** Running task state for parallel execution */
interface RunningTask {
  taskId: string;
  session: ProviderSession;
  logFile: string;
  startTime: Date;
  promise: Promise<ProviderResult>;
  /** The trigger type that caused this task to be spawned */
  triggerType?: string;
