            if (!taskId) {
              return { success: false, message: "Task ID is required for 'claim' action." };
            }
            // Check capacity before claiming
            if (!hasCapacity(agentId)) {
              const activeCount = getActiveTaskCount(agentId);
              const agent = getAgentById(agentId);
